        f'Destination="{d}" '
        f'ProtocolBinding="{pb}" '
        f'AssertionConsumerServiceURL="{acs}" '
        f'ForceAuthn="{"true" if force_authn else "false"}" '
        f'IsPassive="{"true" if is_passive else "false"}"'
