def encode_saml_request(xml: str) -> str:
    return base64.b64encode(xml.encode("utf-8")).decode("ascii")

def build_auto_post_form(idp_destination_url: str, saml_request_b64: str, relay_state: str | None = None) -> str:
    action = html.escape(idp_destination_url, quote=True)
    saml_val = html.escape(saml_request_b64, quote=True)
    inputs = [f'<input type="hidden" name="SAMLRequest" value="{saml_val}"/>']
